export const getGetAuditUrl = (auditId: string,) => {




  return `/api/audits/${auditId}`
}

/**
 * @summary Get an audit with its checks
 */
export const getAudit = async (auditId: string, options?: RequestInit): Promise<AuditDetail> => {

  return customFetch<AuditDetail>(getGetAuditUrl(auditId),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetAuditQueryKey = (auditId: string,) => {
    return [
    `/api/audits/${auditId}`
    ] as const;
    }


export const getGetAuditQueryOptions = <TData = Awaited<ReturnType<typeof getAudit>>, TError = ErrorType<unknown>>(auditId: string, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getAudit>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetAuditQueryKey(auditId);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getAudit>>> = ({ signal }) => getAudit(auditId, { signal, ...requestOptions });





   return  { queryKey, queryFn, enabled: !!(auditId), ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getAudit>>, TError, TData> & { queryKey: QueryKey }
}

export type GetAuditQueryResult = NonNullable<Awaited<ReturnType<typeof getAudit>>>
export type GetAuditQueryError = ErrorType<unknown>


/**
 * @summary Get an audit with its checks
 */

export function useGetAudit<TData = Awaited<ReturnType<typeof getAudit>>, TError = ErrorType<unknown>>(
 auditId: string, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getAudit>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getGetAuditQueryOptions(auditId,options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







